async (params, browser) => {
  // Open Notion page
  await browser.open(`${params.page_url}`)

  // Let page load
  await browser.wait(3000)

  // Update page via Notion API
  const result = await browser.evaluate(`const url = window.location.href; const idMatch = url.match(/([a-f0-9]{32})(?:[?#]|$)/) || url.match(/([a-f0-9-]{36})/); if (!idMatch) throw new Error('Could not extract page ID from URL'); let pageId = idMatch[1]; if (pageId.length === 32) pageId = pageId.replace(/(.{8})(.{4})(.{4})(.{4})(.{12})/, '$1-$2-$3-$4-$5'); const ops = []; const newTitle = params.new_title; if (newTitle) { ops.push({ id: pageId, table: 'block', path: ['properties', 'title'], command: 'set', args: [[ newTitle ]] }); } const appendText = params.append_text; if (appendText) { const blockId = crypto.randomUUID(); ops.push({ id: blockId, table: 'block', path: [], command: 'set', args: { type: 'text', id: blockId, version: 1, alive: true, parent_id: pageId, parent_table: 'block', properties: { title: [[ appendText ]] } } }); ops.push({ id: pageId, table: 'block', path: ['content'], command: 'listAfter', args: { id: blockId } }); } if (ops.length === 0) return { success: false, message: 'No changes specified' }; const resp = await fetch('/api/v3/submitTransaction', { method: 'POST', headers: { 'Content-Type': 'application/json' }, credentials: 'same-origin', body: JSON.stringify({ operations: ops }) }); if (!resp.ok) throw new Error('Update failed: ' + resp.status); return { success: true, page_id: pageId, updated: { title: !!newTitle, appended: !!appendText } }`)

  return result
}
